from langchain.agents import AgentExecutor
from langchain.callbacks import StdOutCallbackHandler

# Wrap your agent execution
def detect_tool_loops(agent_executor: AgentExecutor, max_iterations=5):
    tool_calls = {}

    class LoopDetector(StdOutCallbackHandler):
        def on_tool_start(self, tool, input_str, **kwargs):
            tool_key = f'{tool.name}:{input_str}'
            if tool_key in tool_calls:
                tool_calls[tool_key] += 1
                if tool_calls[tool_key] > max_iterations:
                    raise ValueError(f'Tool loop detected: {tool.name} called {tool_calls[tool_key]} times')
            else:
                tool_calls[tool_key] = 1

    agent_executor.callbacks = [LoopDetector()]
    return agent_executor

