from langchain.agents import AgentExecutor
from langchain.callbacks.base import BaseCallbackHandler
from typing import Dict, Any

class ToolLoopGuard(BaseCallbackHandler):
    tool_history: Dict[str, int] = {}
    MAX_CALLS = 3

    def on_tool_start(self, tool_name: str, **kwargs):
        if tool_name in self.tool_history:
            self.tool_history[tool_name] += 1
            if self.tool_history[tool_name] > self.MAX_CALLS:
                raise ValueError(f'Tool {tool_name} called too many times')
        else:
            self.tool_history[tool_name] = 1

# Apply to agent
agent_executor = AgentExecutor.from_agent_and_tools(
    agent=agent,
    tools=tools,
    callbacks=[ToolLoopGuard()],
    max_iterations=10,
    early_stopping_method='generate'
)

