import vex
from langchain.agents import AgentExecutor
from langchain.chains import RetrievalQA

# Install: pip install langchain vex-sdk

@vex.verify(
    detect=['tool_loops', 'rag_hallucinations', 'context_overflow', 'output_schema'],
    auto_fix=True,
    alert_on='production'
)
def safe_agent_run(agent_executor: AgentExecutor, input_data):
    return agent_executor.invoke(input_data)

@vex.verify(
    max_tokens=4000,
    rag_threshold=0.75,
    output_format='json'
)
def safe_rag_query(retrieval_qa: RetrievalQA, question: str):
    return retrieval_qa.invoke({'query': question})

# Usage - Vex handles everything automatically
result = safe_agent_run(your_agent_executor, {'input': 'user query'})
print(result)
